import sys

def solve():
    import sys
    input = sys.stdin.read
    data = input().split()
    N = int(data[0])
    A = list(map(int, data[1:]))

    if all(a == 1 for a in A):
        print("Yes")
        return

    # Create a copy of A to modify
    A_mod = A[:]

    # Iterate through all positions
    for i in range(N):
        # Check for pattern "ARC" (i, i+1, i+2)
        if i + 2 < N:
            if A_mod[i] == 0 and A_mod[i+1] == 1 and A_mod[i+2] == 1:
                A_mod[i] = 1
        # Check for pattern "CRA" (i-2, i-1, i)
        if i - 2 >= 0:
            if A_mod[i-2] == 1 and A_mod[i-1] == 1 and A_mod[i] == 0:
                A_mod[i-2] = 1
        # Check for pattern "RAC" (i, i+1, i+2) with wrap-around
        if i + 2 < N:
            if A_mod[i] == 0 and A_mod[i+1] == 1 and A_mod[i+2] == 1:
                A_mod[i] = 1
        else:
            if A_mod[i] == 0 and A_mod[(i+1)%N] == 1 and A_mod[(i+2)%N] == 1:
                A_mod[i] = 1
        # Check for pattern "ARC" (i-2, i-1, i) with wrap-around
        if i - 2 >= 0:
            if A_mod[i-2] == 1 and A_mod[i-1] == 1 and A_mod[i] == 0:
                A_mod[i-2] = 1
        else:
            if A_mod[i-2 + N] == 1 and A_mod[i-1 + N] == 1 and A_mod[i] == 0:
                A_mod[i-2 + N] = 1

    if all(a == 1 for a in A_mod):
        print("Yes")
    else:
        print("No")

if __name__ == '__main__':
    solve()
